# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

from flask import Flask, request, redirect, url_for, session, jsonify
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_BASE_URL = 'https://authorization-server.com/oauth/authorize'
TOKEN_URL = 'https://authorization-server.com/oauth/token'
REDIRECT_URI = 'http://localhost:5000/callback'
SCOPE = ['profile', 'email']

@app.route('/login')
def login():
    redirect_uri = url_for('callback', _external=True)
    auth_url = f"{AUTHORIZATION_BASE_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={redirect_uri}&scope={' '.join(SCOPE)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Authorization failed', 401

    token_response = requests.post(
        TOKEN_URL,
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': REDIRECT_URI,
            'client_id': CLIENT_ID,
            'client_secret': CLIENT_SECRET
        }
    )
    
    if token_response.status_code != 200:
        return 'Failed to exchange code for token', 401

    tokens = token_response.json()
    session['access_token'] = tokens['access_token']

    return jsonify(tokens)

if __name__ == '__main__':
    app.run(debug=True)